query:
SELECT sp.competenciaId, sp.competenciaName, sp.progressoTotal, sp.progressoAulas, sp.notaAvaliacao, sp.totalAulas, sp.aulasAssistidas
FROM student_performance sp
WHERE sp.alunoId = 30097 AND (sp.competenciaName LIKE '%Racioc%' OR sp.competenciaName LIKE '%racioc%' OR sp.competenciaName LIKE '%Lógic%');

